class IsPhoneNumber(DirtyEquals[str]):
    """
    A class that checks if a value is a valid phone number, optionally restricted to a specific country's
    national and international formats.
    """

    _delimiters_re = re.compile(r'[\s\-.()]')
    _generic_national_re = re.compile(r'^\d{7,15}$')
    _generic_international_re = re.compile(r'^\d{7,15}$')

    # digit-only rules (delimiters and leading `+` already stripped) keyed by ISO 3166-1 alpha-2 country code
    _country_rules = {
        'US': {
            'national': re.compile(r'^\d{10}$'),
            'international': re.compile(r'^1\d{10}$'),
        },
        'GB': {
            'national': re.compile(r'^0\d{10}$'),
            'international': re.compile(r'^44\d{10}$'),
        },
    }

    def __init__(self, country: Optional[str] = None):
        """
        Args:
            country: ISO 3166-1 alpha-2 country code to validate the phone number against, if omitted, generic
                phone number validation is used.

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber('US')
        assert '(555) 123-4567' == IsPhoneNumber('US')
        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+44 20 7946 0958' == IsPhoneNumber('GB')
        assert '555-123-4567' != IsPhoneNumber('GB')
        assert 'not a number' != IsPhoneNumber()
        ```
        """
        self.country = country
        super().__init__(plain_repr('*') if country is None else repr(country))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        cleaned = self._delimiters_re.sub('', other)
        if not cleaned:
            return False

        has_plus = cleaned.startswith('+')
        digits = cleaned[1:] if has_plus else cleaned
        if not digits.isdigit():
            return False

        rules = self._country_rules.get(self.country.upper()) if self.country else None

        if rules is not None:
            if has_plus:
                return bool(rules['international'].match(digits))
            else:
                return bool(rules['national'].match(digits))
        elif self.country is not None:
            # unrecognised country code, fall back to generic international validation
            return has_plus and bool(self._generic_international_re.match(digits))
        else:
            if has_plus:
                return bool(self._generic_international_re.match(digits))
            else:
                return bool(self._generic_national_re.match(digits))


